parameters.jsCode:
const lines = items.map(item => {
  const binaryKey = Object.keys(item.binary)[0];

  return `file '${item.binary[binaryKey].fileName}'`;
});

const content = lines.join('\n');

return [
  {
    json: {},
    binary: {
      data: {
        data: Buffer.from(content).toString('base64'),
        mimeType: 'text/plain',
        fileName: 'list.txt',
      }
    }
  }
];

