parameters.jsCode:
const orientation = $('Edit Fields14').first().json.orientation;
const audioPath = 'audio.mp3';
const subtitlePath = 'subtitle.ass';
const outputPath = 'output.mp4';
const workDir = 'video_build';

// Resolution based on orientation
const width = orientation === 'horizontal' ? 1920 : 1080;
const height = orientation === 'horizontal' ? 1080 : 1920;
const fps = 30;

// ── Motion Effect Filters ──────────────────────────────────────
// Each effect returns a zoompan filter string
// 'd' = total frames for this clip
function getMotionFilter(effect, totalFrames, w, h) {
  const filters = {
    // Zoom in: start at 1.0, end at 1.3
    zoom_in: `zoompan=z='min(zoom+0.0010,1.3)':x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':d=${totalFrames}:s=${w}x${h}:fps=${fps}`,

    // Zoom out: start at 1.3, end at 1.0
    zoom_out: `zoompan=z='if(eq(on,1),1.3,max(zoom-0.0010,1.0))':x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':d=${totalFrames}:s=${w}x${h}:fps=${fps}`,

    // Pan left: zoom 1.3, move from right to left
    pan_left: `zoompan=z='1.3':x='if(eq(on,1),iw/zoom/2,min(x+1.5,iw-iw/zoom))':y='ih/2-(ih/zoom/2)':d=${totalFrames}:s=${w}x${h}:fps=${fps}`,

    // Pan right: zoom 1.3, move from left to right
    pan_right: `zoompan=z='1.3':x='if(eq(on,1),iw-iw/zoom,max(x-1.5,0))':y='ih/2-(ih/zoom/2)':d=${totalFrames}:s=${w}x${h}:fps=${fps}`,

    // Pan up: zoom 1.3, move from bottom to top
    pan_up: `zoompan=z='1.3':x='iw/2-(iw/zoom/2)':y='if(eq(on,1),ih-ih/zoom,max(y-1.5,0))':d=${totalFrames}:s=${w}x${h}:fps=${fps}`,

    // Pan down: zoom 1.3, move from top to bottom
    pan_down: `zoompan=z='1.3':x='iw/2-(iw/zoom/2)':y='if(eq(on,1),0,min(y+1.5,ih-ih/zoom))':d=${totalFrames}:s=${w}x${h}:fps=${fps}`,

    // Ken Burns in: diagonal zoom in with slight pan
    ken_burns_in: `zoompan=z='min(zoom+0.0008,1.25)':x='if(eq(on,1),0,min(x+0.5,iw-iw/zoom))':y='if(eq(on,1),0,min(y+0.3,ih-ih/zoom))':d=${totalFrames}:s=${w}x${h}:fps=${fps}`,

    // Ken Burns out: diagonal zoom out with slight pan
    ken_burns_out: `zoompan=z='if(eq(on,1),1.25,max(zoom-0.0008,1.0))':x='if(eq(on,1),iw/zoom/4,max(x-0.5,0))':y='if(eq(on,1),ih/zoom/4,max(y-0.3,0))':d=${totalFrames}:s=${w}x${h}:fps=${fps}`,
  };
  return filters[effect] || filters['zoom_in'];
}

// ── Transition duration ────────────────────────────────────────
const transitionDuration = 0.8; // seconds
// ── Build commands ─────────────────────────────────────────────
const commands = [];
const clipFiles = [];

// Phase 1: Generate individual clips with Ken Burns effects
// NOTE: Each clip (except the last) is extended by transitionDuration to
// compensate for xfade overlap. Without this, each xfade transition "eats"
// transitionDuration from total video length, making video shorter than audio.
for (let idx = 0; idx < items.length; idx++) {
  const item = items[idx];
  const step = item.json.step;
  const duration = parseFloat(item.json.audio_duration);
  const effect = item.json.motion_effect || 'zoom_in';
  const imagePath = item.json.image_path || `${step}.png`;
  const clipPath = `${workDir}/clip_${step}.mp4`;
  // Extend clip duration to compensate for xfade overlap
  // Last clip doesn't need extension (no transition after it)
  const isLastClip = (idx === items.length - 1);
  const extraDuration = (isLastClip || items.length === 1) ? 0 : transitionDuration;
  const effectiveDuration = duration + extraDuration;
  const totalFrames = Math.ceil(effectiveDuration * fps);
  const motionFilter = getMotionFilter(effect, totalFrames, width, height);
  // Generate clip: image + zoompan effect
  const cmd = `ffmpeg -y -loop 1 -i "${imagePath}" -vf "${motionFilter}" -t ${effectiveDuration.toFixed(2)} -c:v libx264 -pix_fmt yuv420p -r ${fps} "${clipPath}"`;

  commands.push(cmd);
  clipFiles.push({ step, clipPath, duration: effectiveDuration, transition: item.json.transition || 'none' });
}

// Phase 2: Concatenate clips with transitions
// Build complex filtergraph for xfade transitions
let phase2Command = '';
if (clipFiles.length === 1) {
  // Single clip, no transitions needed
  phase2Command = `ffmpeg -y -i "${clipFiles[0].clipPath}" -i "${audioPath}" -c:v libx264 -c:a aac "${outputPath}"`;
} else {
  // Build xfade filter chain
  const inputFlags = clipFiles.map(c => `-i "${c.clipPath}"`).join(' ');

  let filterChain = '';
  let currentLabel = '[0:v]';
  let cumulativeOffset = 0;

  for (let i = 0; i < clipFiles.length - 1; i++) {
    const clip = clipFiles[i];
    const nextLabel = i === clipFiles.length - 2 ? '[vout]' : `[v${i}]`;
    const transition = clip.transition;

    // Calculate offset: where the transition starts
    // offset = cumulative duration of all previous clips minus transition overlaps
    if (i === 0) {
      cumulativeOffset = clip.duration - transitionDuration;
    } else {
      cumulativeOffset += clip.duration - transitionDuration;
    }

    // Map transition type to ffmpeg xfade transition name
    const xfadeMap = {
      crossfade: 'fade',
      fade_black: 'fadeblack',
      wipe_left: 'wipeleft',
      wipe_right: 'wiperight',
      none: 'fade', // fallback to fade for "none" in middle (last step handled separately)
    };

    const xfadeType = xfadeMap[transition] || 'fade';

    filterChain += `${currentLabel}[${i + 1}:v]xfade=transition=${xfadeType}:duration=${transitionDuration}:offset=${cumulativeOffset.toFixed(2)}${nextLabel};`;

    currentLabel = nextLabel;
  }

  // Remove trailing semicolon
  filterChain = filterChain.replace(/;$/, '');

  // Final command: clips + transitions + audio + subtitle
  phase2Command = `ffmpeg -y ${inputFlags} -i "${audioPath}" -filter_complex "${filterChain}" -map "[vout]" -map "${clipFiles.length}:a" -c:v libx264 -pix_fmt yuv420p -c:a aac "${outputPath}"`;
}
commands.push(phase2Command);
// Phase 3: Add subtitles (burn in)
const finalWithSubs = outputPath.replace('.mp4', '_final.mp4');
commands.push(`ffmpeg -y -i "${outputPath}" -vf "ass=${subtitlePath}" -c:v libx264 -c:a copy "${finalWithSubs}"`);
// ── Return commands ────────────────────────────────────────────
return [
  {
    json: {
      orientation,
      resolution: `${width}x${height}`,
      total_steps: items.length,
      total_commands: commands.length,
      phase1_description: 'Generate individual clips with Ken Burns effects',
      phase2_description: 'Concatenate clips with transitions + add audio',
      phase3_description: 'Burn in subtitles',
      commands: commands,
      commands_joined: commands.join(' && '),
    }
  }
];

// Input: items array dimana setiap item memiliki:
//   - $json.subtitle (teks subtitle dari AI Agent)
//   - $json.audio_duration (durasi dalam detik, dari ffprobe)
//   - $json.step (nomor step)

const header = `[Script Info]
Title: Generated Subtitle
ScriptType: v4.00+
WrapStyle: 0
ScaledBorderAndShadow: yes
YCbCr Matrix: None
PlayResX: 1920
PlayResY: 1080

[V4+ Styles]
Format: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, Underline, StrikeOut, ScaleX, ScaleY, Spacing, Angle, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding
Style: Default,Arial,52,&H00FFFFFF,&H000000FF,&H00000000,&H80000000,-1,0,0,0,100,100,0,0,1,3,1,2,20,20,40,1

[Events]
Format: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text`;

function formatTime(seconds) {
  const h = Math.floor(seconds / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  const s = Math.floor(seconds % 60);
  const cs = Math.round((seconds % 1) * 100);
  return `${h}:${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}.${String(cs).padStart(2, '0')}`;
}

let currentTime = 0;
const dialogueLines = [];

for (const item of items) {
  const duration = parseFloat(item.json.audio_duration);
  const startTime = formatTime(currentTime);
  const endTime = formatTime(currentTime + duration);
  const text = item.json.subtitle;

  dialogueLines.push(`Dialogue: 0,${startTime},${endTime},Default,,0,0,0,,${text}`);
  currentTime += duration;
}

const assContent = header + '\n' + dialogueLines.join('\n');

return [
  {
    json: {},
    binary: {
      subtitle_file: {
        data: Buffer.from(assContent).toString('base64'),
        mimeType: 'text/plain',
        fileName: 'subtitle.ass',
      }
    }
  }
];
